import { cn } from '@/utils/cn';
import ChevronLeft from 'lucide-solid/icons/chevron-left';
import ChevronRight from 'lucide-solid/icons/chevron-right';
import type { Component } from 'solid-js';
import {
  createEffect,
  createMemo,
  createSignal,
  For,
  mergeProps,
  on,
  onCleanup,
  onMount,
  Show,
} from 'solid-js';
import type { CarouselFunction, CarouselProps } from './carousel.types';
const VARIANTS = {
  horizontal: 'car17',
  vertical: 'car18',
};

export const Carousel: Component<CarouselProps> = _p => {
  const p = mergeProps(
    {
      arrows: true,
      autoplay: true,
      autoplaySpeed: 3000,
      dots: true,
      infinite: true,
      effect: 'scrollx' as const,
    },
    _p,
  );

  const [currentIndex, setCurrentIndex] = createSignal(0);
  const [isPlaying, setIsPlaying] = createSignal(!!p.autoplay);
  const [isAnimating, setIsAnimating] = createSignal(false);

  let containerRef: HTMLDivElement | undefined;
  let slidesRef: HTMLDivElement | undefined;
  let autoplayTimer: ReturnType<typeof setInterval> | undefined;

  const totalSlides = () => p.images.length;

  // Animation duration for slide transitions
  const transitionDuration = 400;

  // Clear autoplay timer
  const clearAutoplay = () => {
    if (autoplayTimer) {
      clearInterval(autoplayTimer);
      autoplayTimer = undefined;
    }
  };

  // Animate slide transition using CSS transitions
  const animateTransition = (from: number, to: number) => {
    if (!slidesRef || isAnimating()) return;

    setIsAnimating(true);

    const slides = slidesRef.querySelectorAll('.car03');
    const fromSlide = slides[from] as HTMLElement;
    const toSlide = slides[to] as HTMLElement;

    if (!fromSlide || !toSlide) {
      setIsAnimating(false);
      return;
    }

    const vertical = p.direction === 'vertical';
    const translateProp = vertical ? 'translateY' : 'translateX';

    if (p.effect === 'fade') {
      // Fade effect
      fromSlide.style.zIndex = '1';
      toSlide.style.zIndex = '2';
      toSlide.style.transition = 'none';
      fromSlide.style.transition = 'none';
      toSlide.style.opacity = '0';

      // Force reflow to apply initial state
      void toSlide.offsetHeight;

      // Apply CSS transition and target values
      const transitionValue = 'opacity var(--carousel-transition-duration) ease-in-out';
      fromSlide.style.transition = transitionValue;
      toSlide.style.transition = transitionValue;

      fromSlide.style.opacity = '0';
      toSlide.style.opacity = '1';

      setTimeout(() => {
        slides.forEach((slide, index) => {
          const el = slide as HTMLElement;
          el.style.transition = 'none';
          el.style.opacity = index === to ? '1' : '0';
          el.style.zIndex = index === to ? '1' : '0';
        });
        setIsAnimating(false);
      }, transitionDuration);
    } else {
      // Scrollx effect (default)
      // Use pixel-based transforms with 1px overlap to eliminate sub-pixel gap
      const size = vertical ? slidesRef.offsetHeight : slidesRef.offsetWidth;
      const direction = to > from ? -1 : 1;
      const isWrapping =
        (from === 0 && to === totalSlides() - 1) || (from === totalSlides() - 1 && to === 0);

      let actualDirection = direction;
      if (isWrapping) {
        actualDirection = from === 0 ? 1 : -1;
      }

      // Position the target slide without transition (1px overlap to prevent gap)
      toSlide.style.transition = 'none';
      fromSlide.style.transition = 'none';
      toSlide.style.transform = `${translateProp}(${-actualDirection * (size - 1)}px)`;
      toSlide.style.opacity = '1';

      // Force reflow to apply initial position
      void toSlide.offsetHeight;

      // Apply CSS transition and target values
      const transitionValue = 'transform var(--carousel-transition-duration) ease-in-out';
      fromSlide.style.transition = transitionValue;
      toSlide.style.transition = transitionValue;

      fromSlide.style.transform = `${translateProp}(${actualDirection * size}px)`;
      toSlide.style.transform = `${translateProp}(0px)`;

      setTimeout(() => {
        slides.forEach((slide, index) => {
          const el = slide as HTMLElement;
          el.style.transition = 'none';
          if (index === to) {
            el.style.transform = `${translateProp}(0px)`;
            el.style.opacity = '1';
          } else {
            el.style.transform = `${translateProp}(${size}px)`;
            el.style.opacity = '0';
          }
        });
        setIsAnimating(false);
      }, transitionDuration);
    }
  };

  // Go to specific slide
  const goToSlide = (index: number, skipAnimation = false) => {
    if (isAnimating() && !skipAnimation) return;

    const current = currentIndex();
    let targetIndex = index;

    // Handle boundaries
    if (p.infinite) {
      if (targetIndex < 0) targetIndex = totalSlides() - 1;
      if (targetIndex >= totalSlides()) targetIndex = 0;
    } else {
      if (targetIndex < 0) targetIndex = 0;
      if (targetIndex >= totalSlides()) targetIndex = totalSlides() - 1;
    }

    if (targetIndex === current && !skipAnimation) return;

    p.beforeChange?.(current, targetIndex);

    if (skipAnimation) {
      setCurrentIndex(targetIndex);
      p.afterChange?.(targetIndex);
    } else {
      animateTransition(current, targetIndex);
      setCurrentIndex(targetIndex);
      p.afterChange?.(targetIndex);
    }

    // Reset autoplay timer and progress animation when slide changes
    if (isPlaying() && p.autoplay) {
      clearAutoplay();
      startAutoplay();
    }
  };

  // Navigation functions
  const next = () => goToSlide(currentIndex() + 1);
  const prev = () => goToSlide(currentIndex() - 1);
  const moveTo = (index: number) => goToSlide(index);

  const pause = () => {
    setIsPlaying(false);
    clearAutoplay();
    return {};
  };

  const play = () => {
    if (!p.autoplay) return {};
    setIsPlaying(true);
    startAutoplay();
    return {};
  };

  // Start autoplay
  const startAutoplay = () => {
    if (!p.autoplay || !isPlaying()) return;

    clearAutoplay();

    autoplayTimer = setInterval(() => {
      if (!isAnimating()) {
        next();
      }
    }, p.autoplaySpeed);
  };

  // Export carousel functions
  createEffect(function exportCarouselFunction() {
    const carouselFunction: CarouselFunction = {
      next,
      prev,
      moveTo,
      pause,
      play,
    };
    p.setCarouselFunction?.(carouselFunction);
  });

  // Handle autoplay
  createEffect(
    on(
      () => [p.autoplay, isPlaying()],
      () => {
        if (p.autoplay && isPlaying()) {
          startAutoplay();
        } else {
          clearAutoplay();
        }
      },
    ),
  );

  // Initialize slides
  onMount(() => {
    if (slidesRef) {
      const slides = slidesRef.querySelectorAll('.car03');
      const vertical = p.direction === 'vertical';
      const translateProp = vertical ? 'translateY' : 'translateX';

      slides.forEach((slide, index) => {
        const el = slide as HTMLElement;
        if (p.effect === 'fade') {
          el.style.opacity = index === 0 ? '1' : '0';
          el.style.zIndex = index === 0 ? '1' : '0';
        } else {
          el.style.transform = index === 0 ? `${translateProp}(0%)` : `${translateProp}(100%)`;
          el.style.opacity = index === 0 ? '1' : '0';
        }
      });
    }

    if (p.autoplay) {
      startAutoplay();
    }
  });

  // Cleanup
  onCleanup(function stopAutoplay() {
    clearAutoplay();
  });

  // Handle click on slide
  const handleSlideClick = (index: number) => {
    if (index === currentIndex()) {
      p.onClickSlide?.(index);
    }
  };

  const showPrevArrow = () => p.infinite || currentIndex() > 0;
  const showNextArrow = () => p.infinite || currentIndex() < totalSlides() - 1;

  const isVertical = () => p.direction === 'vertical';

  // Constrain dotPlacement based on direction
  const dotPlacementClass = () => {
    if (isVertical()) {
      // Vertical: only 'start' or 'end' allowed
      if (p.dotPlacement === 'start') return 'car15';
      return 'car16'; // default for vertical
    } else {
      // Horizontal: only 'top' or 'bottom' allowed
      if (p.dotPlacement === 'top') return 'car14';
      return 'car13'; // default for horizontal
    }
  };

  const hasDotDuration = createMemo(
    () => isPlaying() && p.autoplay && typeof p.autoplay === 'object' && p.autoplay.dotDuration,
  );

  return (
    <div
      ref={containerRef}
      class={cn('car01', p.direction && VARIANTS[p.direction], dotPlacementClass(), p.class?.root)}
      style={{
        '--carousel-transition-duration': `${transitionDuration}ms`,
        '--carousel-autoplay-speed': `${p.autoplaySpeed}ms`,
      }}
    >
      {/* Slides container */}
      <div ref={slidesRef} class="car02">
        <For each={p.images}>
          {(image, index) => (
            <div class={cn('car03', p.class?.item)} onClick={() => handleSlideClick(index())}>
              <img {...image} class={cn('car04', image.class)} draggable={false} />
            </div>
          )}
        </For>
      </div>

      {/* Arrows */}
      <Show when={p.arrows}>
        <Show when={showPrevArrow()}>
          <button type="button" class="car05 car06" onClick={prev} aria-label="Previous slide">
            <ChevronLeft class="size-6" />
          </button>
        </Show>
        <Show when={showNextArrow()}>
          <button type="button" class="car05 car07" onClick={next} aria-label="Next slide">
            <ChevronRight class="size-6" />
          </button>
        </Show>
      </Show>

      {/* Dots */}
      <Show when={p.dots && totalSlides() > 1}>
        <div class="car08">
          <For each={p.images}>
            {(_, index) => (
              <button
                type="button"
                class={cn(
                  'car09',
                  currentIndex() === index() && 'car10',
                  hasDotDuration() && 'car11',
                )}
                onClick={() => goToSlide(index())}
                aria-label={`Go to slide ${index() + 1}`}
              >
                <Show when={hasDotDuration()}>
                  <div class="car12" />
                </Show>
              </button>
            )}
          </For>
        </div>
      </Show>
    </div>
  );
};
